  ('Origin Coffee Roasting', 'Coffee Shop / Roastery', '51–100 employees', 'Cape Town, De Waterkant', 'Origin Coffee Roasting is one of South Africa''s most respected specialty coffee brands, with their flagship café and roastery in De Waterkant. They roast single-origin beans in-house and are known for their meticulous approach to coffee quality and barista training.', 'origincoffee.co.za', 'https://logo.clearbit.com/origincoffee.co.za', true),
  ('The Marine Hermanus', 'Boutique Hotel', '11–50 employees', 'Hermanus, Western Cape', 'The Marine Hermanus is a historic boutique hotel perched above the Walker Bay coastline, one of the world''s premier whale-watching destinations. Offering luxury accommodation, fine dining, and a seafront pool in one of Africa''s most spectacular natural settings.', NULL, NULL, true),
  ('KFC South Africa', 'Fast Food Chain', '1 000+ employees', 'Johannesburg (HQ) · Nationwide', 'KFC South Africa is one of the country''s largest and most beloved fast-food chains, operating over 900 restaurants nationwide. Part of the global Yum! Brands family, KFC SA is deeply embedded in South African culture, from township outlets to highway stops. With one of the broadest geographic footprints of any restaurant chain in SA, KFC offers wide employment across all nine provinces.', 'kfc.co.za', 'https://logo.clearbit.com/kfc.co.za', true),
  ('McDonald''s South Africa', 'Fast Food Chain', '1 000+ employees', 'Johannesburg (HQ) · Nationwide', 'McDonald''s South Africa operates over 340 restaurants nationwide and is committed to being a significant local employer. As part of one of the world''s most recognised brands, McDonald''s SA brings international training standards, a strong focus on food safety, and genuine career development for crew members at all levels.', 'mcdonalds.co.za', 'https://logo.clearbit.com/mcdonalds.co.za', true),
